import OpenAI from 'openai';
import { VexClient } from 'vex-sdk';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

export async function POST(request: Request) {
  const event = await request.json();

  if (event.type === 'thread.run.completed') {
    const run = await openai.beta.threads.runs.retrieve(
      event.data.thread_id,
      event.data.id
    );

    // Vex verification
    const results = await vex.verify({
      input: run.model,
      output: run.last_error || run.required_action,
      metadata: {
        regulation: 'HIPAA',
        check_phipolicy: true,
        schema: 'fda_medical_dosage_v1'
      }
    }, 'healthcare-assistants-policy');

    if (!results.passed) {
      await openai.beta.threads.runs.cancel(
        event.data.thread_id,
        event.data.id
      );
      return new Response('Blocked: Compliance failure', { status: 403 });
    }
  }

  return new Response('OK');
}
